const body = $input.first().json.body || $input.first().json;

const tenant_id = (body.tenant_id || '').trim();
const query = (body.query || '').trim();
const top_k = body.top_k || 3;

if (!tenant_id) throw new Error('tenant_id fehlt');
if (!query) throw new Error('query fehlt');

return [{ json: { tenant_id, query, top_k } }];

const validated = $('Validieren').first().json;
const embeddingResponse = $input.first().json;
const embedding = embeddingResponse.embeddings[0];
const embeddingStr = '[' + embedding.join(',') + ']';

return [{ json: {
  tenant_id: validated.tenant_id,
  query: validated.query,
  top_k: validated.top_k,
  embedding: embeddingStr
}}];

const query = $('Validieren').first().json.query;
const results = $input.all().map(item => item.json);

if (results.length === 0) {
  return [{ json: { query, context: '', has_context: false, prompt: query } }];
}

const context = results
  .map((r, i) => `[${i+1}] ${r.content}`)
  .join('\n\n');

const prompt = `Du bist ein hilfreicher Assistent. Beantworte die Frage basierend auf dem folgenden Kontext. Antworte auf Deutsch. Wenn der Kontext die Frage nicht beantwortet, sage das ehrlich.\n\nKontext:\n${context}\n\nFrage: ${query}\n\nAntwort:`;

return [{ json: { query, context, has_context: true, prompt, result_count: results.length } }];

const llmResponse = $input.first().json;
const promptData = $('Prompt bauen').first().json;

let answer = (llmResponse.response || '').trim();

// Remove <think> blocks if present
answer = answer.replace(/<think>[\s\S]*?<\/think>/g, '').trim();

return [{ json: {
  answer,
  query: promptData.query,
  sources_used: promptData.result_count || 0,
  has_context: promptData.has_context
}}];
